export const validateEmail = (email: string): boolean => {
    return email.split('@').length === 2;
}

export const validateName = (name: string): boolean => {
    if (name.length <= 2 || name.length > 255) return false
    const regex = /^[a-zA-ZÀ-ú\s]+$/;
    return regex.test(name);
}

export const formatPhone = (originalPhone: string): string => {
    let phone = originalPhone.replace(/\D/g, '');

    if (phone.length === 0) {
        return '';
    }
    else if (phone.length <= 2) {
        return `(${phone}`;
    } else if (phone.length <= 6) {
        const ddd = phone.substring(0, 2);
        const numero = phone.substring(2);
        return `(${ddd}) ${numero}`;
    } else if (phone.length <= 10) {
        const ddd = phone.substring(0, 2);
        const prefixo = phone.substring(2, 6);
        const sufixo = phone.substring(6, phone.length);
        return `(${ddd}) ${prefixo}-${sufixo}`;
    }
    else if (phone.length >= 11) {
        const ddd = phone.substring(0, 2);
        const prefixo = phone.substring(2, 7);
        const sufixo = phone.substring(7, 11);
        return `(${ddd}) ${prefixo}-${sufixo}`;
    }
    return phone;
}

export const validatePhone = (originalPhone: string): boolean => {
    let phone = originalPhone.replace(/\D/g, '');
    return phone.length === 10 || phone.length === 11;
}

